package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Locator;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP21CrearPedidoCantidadMinimaPlaywrightTest extends BaseTestPlaywright {    @Test    void crearPedidoConCantidadMinimaUno() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("camarero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForLoadState();        page.locator("a:has-text('Crear pedido'), a:has-text('Crear Pedido')")                .first()                .click();        page.waitForLoadState();        Locator selectorProductos = page.locator("select").first();        assertTrue(                selectorProductos.count() > 0,                "No se encontró el selector de productos."        );        String valueProducto = selectorProductos.locator("option").nth(1).getAttribute("value");        String nombreProducto = selectorProductos.locator("option").nth(1).textContent();        selectorProductos.selectOption(valueProducto);        page.locator("input[type='number']")                .first()                .fill("1");        page.locator("button:has-text('Agregar')")                .first()                .click();        page.waitForTimeout(1000);        String contenidoAntesGuardar = page.content();        assertTrue(                contenidoAntesGuardar.contains("Total:")                        && !contenidoAntesGuardar.contains("Total: S/. 0.00"),                "El sistema no aceptó la cantidad mínima de 1 unidad."        );        page.locator("button:has-text('Guardar Pedido'), button:has-text('Guardar pedido')")                .first()                .click();        page.waitForLoadState();        page.waitForTimeout(1500);        String contenidoFinal = page.content();        assertTrue(                contenidoFinal.contains("Pedidos Actuales")                        || contenidoFinal.contains("Pendiente")                        || contenidoFinal.contains("pending")                        || contenidoFinal.contains(nombreProducto.trim()),                "El pedido con cantidad mínima 1 no se registró correctamente."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get("evidencias/HP21-crear-pedido-cantidad-minima.png"))                        .setFullPage(true)        );    }}